import React from 'react'
import styles from './styles.module.scss'
import TextField from '@mui/material/TextField'
import Button from '@mui/material/Button'
import { v4 as uuidv4 } from 'uuid'
import { useNavigate } from 'react-router'
import { saveLocalPack } from '../../localStorage/localPacks'
import dayjs from 'dayjs'
import { format } from '../../consts.js'

const examples = [
  'Вопросы от славян',
  'Игры, музыка и многое другое',
  'Кинопак',
  'Аниме и прочий буллщит',
  'Мемная Солянка',
]
const randomPlaceholder = examples[Math.floor(Math.random() * examples.length)]

export default function NewPack() {
  const [packName, setPackName] = React.useState('')
  const navigate = useNavigate()

  const createPack = async () => {
    const uuid = uuidv4()
    const pack = {
      uuid,
      name: packName,
      date: dayjs().format('DD.MM.YYYY'),
      creationTime: Date.now(),
      language: '',
      version: format.latestVersion,
      difficulty: 5,
      rounds: [],
    }
    await saveLocalPack(pack)
    navigate(`/pack/${uuid}`)
  }

  const handleCheckSubmit = e => {
    if (e.key === 'Enter') createPack()
  }

  return (
    <div className={styles.container}>
      <TextField
        label='Название пака'
        variant='outlined'
        value={packName}
        onChange={e => setPackName(e.target.value)}
        className={styles.field}
        placeholder={randomPlaceholder}
        onKeyUp={handleCheckSubmit}
      />
      <Button variant='contained' onClick={() => createPack()} disabled={!packName.length}>
        Создать
      </Button>
    </div>
  )
}
